import{_ as d,o as r,c as a,ag as e}from"./chunks/framework.DXGyWiRo.js";const q=JSON.parse('{"title":"伯克希尔·哈撒韦公司业绩与标普500指数对比","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2009年/翻译.md","filePath":"01_letters/2009年/翻译.md"}'),o={name:"01_letters/2009年/翻译.md"};function p(n,t,l,i,h,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="伯克希尔·哈撒韦公司业绩与标普500指数对比" tabindex="-1">伯克希尔·哈撒韦公司业绩与标普500指数对比 <a class="header-anchor" href="#伯克希尔·哈撒韦公司业绩与标普500指数对比" aria-label="Permalink to &quot;伯克希尔·哈撒韦公司业绩与标普500指数对比&quot;">​</a></h1><h2 id="每股账面价值年度百分比变化" tabindex="-1">每股账面价值年度百分比变化 <a class="header-anchor" href="#每股账面价值年度百分比变化" aria-label="Permalink to &quot;每股账面价值年度百分比变化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>伯克希尔每股账面价值变化 (1)</th><th>标普500含分红回报 (2)</th><th>相对表现 (1)-(2)</th></tr></thead><tbody><tr><td>1965</td><td>23.8%</td><td>10.0%</td><td>+13.8%</td></tr><tr><td>1966</td><td>20.3%</td><td>(11.7%)</td><td>+32.0%</td></tr><tr><td>1967</td><td>11.0%</td><td>30.9%</td><td>(19.9%)</td></tr><tr><td>1968</td><td>19.0%</td><td>11.0%</td><td>+8.0%</td></tr><tr><td>1969</td><td>16.2%</td><td>(8.4%)</td><td>+24.6%</td></tr><tr><td>1970</td><td>12.0%</td><td>3.9%</td><td>+8.1%</td></tr><tr><td>1971</td><td>16.4%</td><td>14.6%</td><td>+1.8%</td></tr><tr><td>1972</td><td>21.7%</td><td>18.9%</td><td>+2.8%</td></tr><tr><td>1973</td><td>4.7%</td><td>(14.8%)</td><td>+19.5%</td></tr><tr><td>1974</td><td>5.5%</td><td>(26.4%)</td><td>+31.9%</td></tr><tr><td>1975</td><td>21.9%</td><td>37.2%</td><td>(15.3%)</td></tr><tr><td>1976</td><td>59.3%</td><td>23.6%</td><td>+35.7%</td></tr><tr><td>1977</td><td>31.9%</td><td>(7.4%)</td><td>+39.3%</td></tr><tr><td>1978</td><td>24.0%</td><td>6.4%</td><td>+17.6%</td></tr><tr><td>1979</td><td>35.7%</td><td>18.2%</td><td>+17.5%</td></tr><tr><td>1980</td><td>19.3%</td><td>32.3%</td><td>(13.0%)</td></tr><tr><td>1981</td><td>31.4%</td><td>(5.0%)</td><td>+36.4%</td></tr><tr><td>1982</td><td>40.0%</td><td>21.4%</td><td>+18.6%</td></tr><tr><td>1983</td><td>32.3%</td><td>22.4%</td><td>+9.9%</td></tr><tr><td>1984</td><td>13.6%</td><td>6.1%</td><td>+7.5%</td></tr><tr><td>1985</td><td>48.2%</td><td>31.6%</td><td>+16.6%</td></tr><tr><td>1986</td><td>26.1%</td><td>18.6%</td><td>+7.5%</td></tr><tr><td>1987</td><td>19.5%</td><td>5.1%</td><td>+14.4%</td></tr><tr><td>1988</td><td>20.1%</td><td>16.6%</td><td>+3.5%</td></tr><tr><td>1989</td><td>44.4%</td><td>31.7%</td><td>+12.7%</td></tr><tr><td>1990</td><td>7.4%</td><td>(3.1%)</td><td>+10.5%</td></tr><tr><td>1991</td><td>39.6%</td><td>30.5%</td><td>+9.1%</td></tr><tr><td>1992</td><td>20.3%</td><td>7.6%</td><td>+12.7%</td></tr><tr><td>1993</td><td>14.3%</td><td>10.1%</td><td>+4.2%</td></tr><tr><td>1994</td><td>13.9%</td><td>1.3%</td><td>+12.6%</td></tr><tr><td>1995</td><td>43.1%</td><td>37.6%</td><td>+5.5%</td></tr><tr><td>1996</td><td>31.8%</td><td>23.0%</td><td>+8.8%</td></tr><tr><td>1997</td><td>34.1%</td><td>33.4%</td><td>+0.7%</td></tr><tr><td>1998</td><td>48.3%</td><td>28.6%</td><td>+19.7%</td></tr><tr><td>1999</td><td>0.5%</td><td>21.0%</td><td>(20.5%)</td></tr><tr><td>2000</td><td>6.5%</td><td>(9.1%)</td><td>+15.6%</td></tr><tr><td>2001</td><td>(6.2%)</td><td>(11.9%)</td><td>+5.7%</td></tr><tr><td>2002</td><td>10.0%</td><td>(22.1%)</td><td>+32.1%</td></tr><tr><td>2003</td><td>21.0%</td><td>28.7%</td><td>(7.7%)</td></tr><tr><td>2004</td><td>10.5%</td><td>10.9%</td><td>(0.4%)</td></tr><tr><td>2005</td><td>6.4%</td><td>4.9%</td><td>+1.5%</td></tr><tr><td>2006</td><td>18.4%</td><td>15.8%</td><td>+2.6%</td></tr><tr><td>2007</td><td>11.0%</td><td>5.5%</td><td>+5.5%</td></tr><tr><td>2008</td><td>(9.6%)</td><td>(37.0%)</td><td>+27.4%</td></tr><tr><td>2009</td><td>19.8%</td><td>26.5%</td><td>(6.7%)</td></tr><tr><td><strong>1965-2009年复合年均增长率</strong></td><td><strong>20.3%</strong></td><td><strong>9.3%</strong></td><td><strong>11.0%</strong></td></tr><tr><td><strong>1964-2009年总收益</strong></td><td><strong>434,057%</strong></td><td><strong>5,430%</strong></td><td></td></tr></tbody></table><blockquote><p><strong>注：</strong> 数据采用财年计算（1965和1966年为截至9月30日的年度；1967年为截至12月31日的15个月）。自1979年起，会计准则要求保险公司按市值而非此前的成本与市价孰低法计量其持有的权益证券。本表中伯克希尔1978年以前的结果已按变更后的准则进行重述。在其他所有方面，结果均采用最初报告的数据计算。</p><p>标普500数据为税前数据，而伯克希尔数据为税后数据。如果伯克希尔这类公司简单地持有标普500并计提应缴税款，其结果将在该指数正回报年份落后于标普500，但在该指数负回报年份超越标普500。多年来，税收成本将导致累计落后幅度相当可观。</p></blockquote><hr><h1 id="伯克希尔·哈撒韦公司" tabindex="-1">伯克希尔·哈撒韦公司 <a class="header-anchor" href="#伯克希尔·哈撒韦公司" aria-label="Permalink to &quot;伯克希尔·哈撒韦公司&quot;">​</a></h1><h2 id="致各位股东" tabindex="-1">致各位股东： <a class="header-anchor" href="#致各位股东" aria-label="Permalink to &quot;致各位股东：&quot;">​</a></h2><p>2009年，我们的净资产增加了218亿美元，使我们A类和B类股票的每股账面价值均增长了19.8%。过去45年（即现任管理层接管以来），账面价值从19美元增长到84,487美元，复合年增长率为20.3%。*</p><p>伯克希尔近期收购的伯灵顿北方圣太菲铁路公司（BNSF）为我们增加了至少65,000名股东，使我们的股东总数达到约50万人。我和我的长期合作伙伴查理·芒格都希望所有股东都能了解伯克希尔的运营、目标、限制和文化。因此，在每年的年度报告中，我们都会阐述指导我们的经济原则。今年这些原则出现在第89至94页，我强烈建议所有股东——尤其是新股东——阅读这些内容。伯克希尔几十年来一直坚持这些原则，在我离开之后也会继续坚持下去。</p><p>在本封信中，我们还将回顾我们业务的一些基本要素，希望能为BNSF的新股东提供一次入门介绍，同时为伯克希尔的老股东提供一次复习。</p><h2 id="我们的衡量标准" tabindex="-1">我们的衡量标准 <a class="header-anchor" href="#我们的衡量标准" aria-label="Permalink to &quot;我们的衡量标准&quot;">​</a></h2><p>我们用于评估管理绩效的指标列示在上一页。从一开始，查理和我就相信应该用一个理性且不变的标准来衡量我们所取得的——或未能取得的——成就。这使我们免于受到诱惑，不会在业绩箭头落地后去画靶心。</p><p>选择标普500作为我们的基准是一个很容易的决定，因为我们的股东几乎可以零成本地通过持有指数基金来匹配其表现。他们为什么要花钱让我们简单地复制这个结果呢？</p><p>对我们来说更困难的决定是如何衡量伯克希尔相对标普500的进步。简单地使用我们股价的变化有充分的理由。事实上，长期来看，这是最好的检验标准。但年度市场价格可能非常不稳定。即使是涵盖十年之久的评估，也可能因测量期期初或期末的愚蠢高价或低价而严重失真。微软的史蒂夫·鲍尔默和通用电气的杰夫·伊梅尔特可以告诉你们这个问题，因为他们接任管理层时公司股价都高得离谱。</p><p>衡量我们年度进步的理想标准是伯克希尔每股内在价值的变化。遗憾的是，这一价值无法以任何接近精确的程度计算，因此我们使用一个粗略的替代指标：每股账面价值。使用这一标准有其缺点，我们将在第92和93页讨论。此外，大多数公司的账面价值都低估了内在价值，伯克希尔当然也是如此。总体而言，我们的业务价值远高于账面上记录的金额。更重要的是，在我们的保险业务中，这一差异是巨大的。尽管如此，查理和我都相信，我们的账面价值——尽管被低估——提供了追踪内在价值变化最有用的工具。按照这一衡量标准，正如本信开篇所述，我们自1965财年开始以来的账面价值以20.3%的复合年增长率增长。</p><p>*本报告中使用的所有每股数据均适用于伯克希尔的A股票。B股票的数据为A股票数据的1/1500。</p><hr><p>值得指出的是，如果我们选择市场价格作为我们的衡量标准，伯克希尔的结果看起来会更好，显示自1965财年以来复合年增长率为22%。令人惊讶的是，这种年度复合率的温和差异导致整个45年期间的市场价值收益达到801,516%，而账面价值收益仅为434,057%（如第2页所示）。我们的市场收益表现更好是因为1965年伯克希尔股票以其盈利不佳的纺织资产的账面价值适当折扣出售，而今天伯克希尔股票通常以其一流业务的会计价值溢价出售。</p><p>总之，第2页的表格传达了三条信息，两条积极，一条非常消极。首先，从1965-1969年开始到2005-09年结束的五年期，我们从未有过任何一个（共有41个这样的五年期）账面价值增长不超过标普500增长的。其次，尽管在标普500上涨的某些年份我们落后于它，但在该指数下跌的11个年份中，我们始终表现得比标普500更好。换句话说，我们的防守比进攻更好，这种状况可能会继续下去。</p><p>最大的问题是，随着我们规模的增长，我们的业绩优势已经大幅缩小，这是一个肯定会继续下去的不利趋势。诚然，伯克希尔拥有许多优秀的企业和一批真正杰出的管理者，他们在一个独特的企业文化中工作，能够最大限度地发挥才能。查理和我相信，这些因素将继续在长期内产生高于平均水平的结果。但巨额资金会自己铸造锚索，我们未来的优势（如果有的话）将只是我们历史优势的一小部分。</p><h2 id="我们不做什么" tabindex="-1">我们不做什么 <a class="header-anchor" href="#我们不做什么" aria-label="Permalink to &quot;我们不做什么&quot;">​</a></h2><p>很久以前，查理表达了他最强烈的愿望：&quot;我只想知道我会死在哪里，这样我就永远不会去那里。&quot; 这句智慧的箴言受普鲁士伟大数学家雅可比的启发，他建议&quot;逆向，始终逆向&quot;作为解决困难问题的辅助方法。（我也可以报告，这种逆向方法在较低的层面也很有效：倒唱一首乡村歌曲，你会很快找回你的车、房子和妻子。）</p><p>以下是我们在伯克希尔应用查理思维的几个例子：</p><ul><li><p>查理和我避免那些我们无法评估其未来的企业，无论其产品多么令人兴奋。过去，人们无需多少远见就能预见汽车（1910年）、飞机（1930年）和电视机（1950年）等行业将迎来的惊人增长。但这些行业的未来还包括竞争动态，这将摧毁几乎所有进入这些行业的企业。即使是幸存者也往往伤痕累累。</p><p>仅仅因为查理和我能清楚地看到一个行业将出现剧增增长，并不意味着我们能够判断当众多竞争对手争夺霸权时，其利润率和资本回报率会是多少。在伯克希尔，我们会坚持那些未来几十年利润前景看起来相当可预测的企业。即便如此，我们仍会犯很多错误。</p></li><li><p>我们永远不会依赖陌生人的善意。&quot;大到不能倒&quot;不是伯克希尔的退路。相反，我们总是会安排我们的事务，使我们可能需要的任何现金需求与我们自身的流动性相比都相形见绌。此外，我们的流动性将通过我们众多且多元化的业务所带来的滚滚收益不断得到补充。</p><p>当金融系统在2008年9月陷入心脏骤停时，伯克希尔是流动性和资本的供应者，而不是求助者。在危机的最顶峰，我们向商业世界投入了155亿美元，否则它只能向联邦政府寻求帮助。其中，90亿美元用于支持三家备受尊敬、此前安全无虞的美国企业，它们迫切需要——刻不容缓——我们切实的信任票。剩余的65亿美元履行了我们帮助资助收购箭牌公司的承诺，这笔交易在恐慌蔓延其他地方时顺利完成。</p></li><li><p>我们为保持首屈一指的财务实力付出了高昂代价。我们通常持有的200多亿美元现金等价物目前收益微薄。但我们睡得很香。</p></li><li><p>我们倾向于让我们众多子公司自主运营，而不对其进行任何程度的监督和监控。这意味着我们有时会发现管理问题较晚，而且运营和资本决策偶尔会做出——如果咨询查理和我——我们会不同意的决定。然而，我们的大多数管理者都非常出色地利用了我们赋予他们的独立性，以维护一种以所有者为导向的态度来回报我们的信任，这种态度是无价的，在大型组织中很少见。我们宁愿承受一些糟糕决策的可见成本，也不愿因繁文缛节导致决策太慢——或根本不做出——而产生许多看不见的成本。</p><p>随着我们对BNSF的收购，我们现在拥有约257,000名员工和数百个不同的运营单位。我们希望两者都能更多。但我们永远不会让伯克希尔变成一个被委员会、预算演示和多层管理层所淹没的庞然大物。相反，我们计划作为一个独立管理的中型和大型企业集合来运营，其中大多数决策发生在运营层面。查理和我将把自己限制在资本配置、控制企业风险、选择管理者和设定薪酬上。</p></li><li><p>我们不试图取悦华尔街。基于媒体或分析师评论买卖股票的投资者不适合我们。相反，我们希望合作伙伴加入伯克希尔，因为他们希望对自己理解的企业进行长期投资，并且该企业遵循他们认同的政策。如果查理和我要进入一个有几个合作伙伴的小型合资企业，我们会寻找与我们步调一致的个体，知道共同的目标和共同的命运会在业主和管理者之间促成幸福的商业&quot;婚姻&quot;。扩大到巨型规模并不会改变这一事实。</p><p>为了建立兼容的股东群体，我们试图直接和翔实地与我们的股东沟通。我们的目标是告诉你们，如果我们立场互换，我们想知道什么。此外，我们试图在周末尽早发布我们的季度和年度财务信息，从而给你们和其他投资者在非交易时段充足的时间来消化在我们的多元化企业发生的事情。（偶尔，SEC的截止日期会迫使我们在非周五披露。）这些事项根本无法在几段话中充分总结，也不适合记者有时寻求的那种引人注目的标题。</p><p>去年我们有一次看到简讯式报道出了什么问题。在这封年度信函的12,830个单词中，有这样一句话：&quot;例如，我们确信，2009年整个经济将陷入混乱——可能还会持续更久——但这一结论并不能告诉我们市场是涨是跌。&quot;许多新闻机构确实报道了——实际上是吹嘘了——这句话的前半部分，而对后半部分只字未提。我认为这是糟糕的新闻业：被误导的读者或观众可能认为查理和我是在预测股票市场的坏事，尽管我们不仅在那句话中，而且在其他地方都明确表示我们根本没有在预测市场。任何被耸人听闻的报道所误导的投资者都付出了高昂的代价：发布这封信当天道琼斯指数收盘于7,063点，年末收于10,428点。</p><p>鉴于我们有过这样的经历，你们可以理解为什么我更倾向于与我们保持尽可能直接和不加删减的沟通。</p></li></ul><hr><p>让我们来详细了解伯克希尔的运营情况。我们有四个主要运营部门，每个部门在资产负债表和损益表特征上与其他部门都不同。因此，正如财务报表标准所做的那样，将它们合并在一起会阻碍分析。所以我们将把它们作为四个独立的企业来呈现，这正是查理和我的看法。</p><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><p>我们的财产意外险（P/C）保险业务一直是伯克希尔增长的引擎，并将继续如此。它为我们创造了奇迹。我们在账面上将我们的P/C公司按其净有形资产高出155亿美元的价值记录，这一金额记在我们的&quot;商誉&quot;账户中。然而，这些公司的价值远超其账面价值——而以下对P/C行业经济模型的介绍将告诉你们原因。</p><p>保险公司预先收取保费，之后才支付赔付。在极端情况下，如某些工伤事故导致的赔付，支付可能持续数十年。这种&quot;先收后付&quot;的模式使我们持有大量资金——我们称之为&quot;浮存金&quot;——这些资金最终将归他人所有。同时，我们可以为伯克希尔的利益投资这些浮存金。尽管个别保单和赔付来来去去，但我们持有的浮存金相对于保费规模保持得非常稳定。因此，随着我们的业务增长，我们的浮存金也在增长。</p><p>如果保费超过费用和最终赔付的总和，我们就获得了承保利润，这增加了浮存金产生的投资收益。这种组合使我们能够享受使用免费资金的好处——更好的是，还能因为持有它而获得报酬。遗憾的是，这种快乐结果的希望吸引了激烈的竞争，在大多数年份竞争是如此激烈，以至于P/C行业整体上承受着显著的承保损失。这种损失实际上是该行业为持有其浮存金所付出的代价。通常这个成本相当低，但在某些灾难深重的年份，承保损失的成本会完全抵消使用浮存金所产生的收入。</p><p>以我可能带有偏见的观点来看，伯克希尔拥有世界上最好的大型保险业务。而且我可以绝对肯定地说，我们拥有最好的管理者。我们的浮存金从1967年进入该业务时的1,600万美元增长到2009年底的620亿美元。此外，我们现在已连续七年实现承保盈利。我相信我们很可能在未来大多数年份——当然不是所有年份——继续实现承保盈利。如果我们做到这一点，我们的浮存金将是免费的，就像有人在我们这里存了620亿美元让我们为自己的利益投资而无需支付利息一样。</p><p>让我再次强调，免费的浮存金并不是P/C行业整体可以期待的结果：在大多数年份，保费不足以覆盖赔付加费用。因此，该行业整体的有形权益回报率几十年来远低于标普500的回报率。伯克希尔之所以存在出色的经济效益，是因为我们有一些杰出的管理者在经营一些不寻常的业务。我们的保险CEO们值得你们的感谢，他们为伯克希尔的价值增加了数十亿美元。很高兴向你们介绍这些全明星。</p><hr><p>让我们从GEICO开始，你们都知道它，因为其每年8亿美元的广告预算（接近汽车保险领域第二大广告商的两倍）。GEICO由Tony Nicely管理，他18岁加入公司。现在66岁的Tony仍然每天跳着踢踏舞去办公室，就像79岁的我一样。我们都觉得能在自己热爱的事业中工作是幸运的。</p><p>GEICO的客户对公司也有好感。证据如下：自伯克希尔1996年取得GEICO控制权以来，其市场份额从2.5%增长到8.1%，这一增长反映了净增700万保单持有人。也许他们联系我们是因为觉得我们的壁虎很可爱，但他们从我们这里购买是为了节省可观的费用。（也许你也可以；拨打1-800-847-7536或访问www.GEICO.com。）他们留下来是因为他们既喜欢我们的服务也喜欢我们的价格。</p><p>伯克希尔分两个阶段收购了GEICO。1976-80年间，我们以4,700万美元购买了约三分之一的股票。多年来，公司大量回购自己的股份，使我们的持股比例增长到约50%，而我们没有再购买任何股份。然后，1996年1月2日，我们以23亿美元现金收购了GEICO剩余的50%，大约是我们最初购买成本的50倍。</p><p>一个古老的华尔街笑话很接近我们的经历：</p><blockquote><p>客户：谢谢你把我放进XYZ股票，买入价5。我听说它涨到了18。 经纪人：是的，这只是开始。事实上，公司现在经营得这么好，18元买入比您当初购买时更划算。 客户：该死，我就知道我应该等一等。</p></blockquote><p>GEICO的增长可能在2010年放缓。美国汽车登记数量实际上因汽车销售低迷而下降。此外，高失业率导致越来越多的司机无保险驾驶。（这在几乎所有地方都是违法的，但如果你失业了还想开车……）然而，我们的&quot;低成本生产商&quot;地位肯定会在未来给我们带来显著增长。1995年，GEICO是美国第六大汽车保险公司；现在我们是第三。公司的浮存金从27亿美元增长到96亿美元。同样重要的是，在伯克希尔拥有GEICO的14年中，有13年实现了承保盈利。</p><p>我在1951年1月第一次以20岁学生的身份访问GEICO时就对它感到兴奋。多亏了Tony，我今天更加兴奋。</p><hr><p>伯克希尔历史上一个极其重要的事件发生在1985年的一个星期六。Ajit Jain走进我们在奥马哈的办公室——我立即知道我们找到了一位超级明星。（他是被Mike Goldberg发现的，Mike现在已被提升为圣Mike。）</p><p>我们立即让Ajit负责National Indemnity规模小且陷入困境的再保险业务。多年来，他将这项业务打造成了保险界独一无二的巨头。</p><p>如今仅有30名员工的Ajit的运营团队在保险的多个领域创下了交易规模纪录。Ajit承保数十亿美元限额——然后将每一分风险都保留下来，而不是分保给其他保险公司。三年前，他接管了劳合社的巨额负债，使其能够清理与27,972名参与者（&quot;names&quot;）的关系，这些人曾承保问题缠身的保单，一度威胁到这家322年历史的机构的生存。那一份合同的保费就达71亿美元。2009年，他谈成了一份人寿再保险合同，可能在未来约50年里为我们带来500亿美元的保费。Ajit的业务恰恰与GEICO相反。在GEICO，我们有数百万份小保单，大多年复一年地续保。Ajit承保的保单相对较少，且组合每年都有显著变化。在世界各地，当有非常巨大且不寻常的事物需要保险时，他是人们会找的人。</p><p>如果查理、我和Ajit同在一条沉船上——而你只能救我们中的一个——游向Ajit。</p><hr><p>我们的第三个保险巨头是General Re。几年前这项业务陷入困境；现在它是我们保险皇冠上闪亮的明珠。</p><p>在Tad Montross的领导下，General Re在2009年取得了出色的承保业绩，同时每美元保费为我们带来了异常大量的浮存金。除了General Re的P/C业务外，Tad和他的同事还发展了一项重要的人寿再保险业务，其价值日益增长。去年，General Re终于取得了Cologne Re的100%所有权，自1995年以来，Cologne Re一直是我们全球布局的关键——尽管只是部分持股——组成部分。Tad和我将于9月访问科隆，感谢其管理者对伯克希尔的重要贡献。</p><p>最后，我们拥有一组较小的公司，其中</p>',49)])])}const c=d(o,[["render",p]]);export{q as __pageData,c as default};
